/*
 * Return the product of the vector x with every odd indexed element inverted.
 * i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
 * Example:
 * input: [4, 2, 10, 4, 5]
 * output: 25
 */
inline double productWithInverses(const std::vector<double>& x) {
    if (x.empty()) return 1.0;

    double result = 1.0;

    /* We parallelise the single loop.  The OpenMP reduction
     * clause automatically combines the thread‑local results
     * with the multiplication operator.  This eliminates the
     * temporary vector and further reduces memory traffic.
     */
#pragma omp parallel for reduction(*:result)
    for (std::size_t i = 0; i < x.size(); ++i) {
        double val = (i & 1) ? 1.0 / x[i] : x[i];
        result *= val;
    }

    return result;
}
