#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* In the vector x negate the odd values and divide the even values by 2.
   Example:
   input: [16, 11, 12, 14, 1, 0, 5]
   output: [8, -11, 6, 7, -1, 0, -5]  */
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();
    if (n == 0) return;

    /* Parallel loop with static scheduling; size is typically large enough
       to amortise the thread‑creation cost.  */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int v = x[i];
        /* Even numbers have the least‑significant bit cleared, odd numbers
           have it set.  We use a bitwise test instead of %2 to avoid a
           modulo operation.  */
        if ((v & 1) == 0) {
            x[i] = v >> 1;          // divide by 2 for even numbers
        } else {
            x[i] = -v;              // negate odd numbers
        }
    }
}
