void reversePrefixSum(std::vector<int> const& x, std::vector<int> &output) {
    // Ensure output has the same size as x.
    output.resize(x.size());

    // Compute the reverse prefix sum in a single linear scan.
    int sum = 0;
    for (std::ptrdiff_t i = static_cast<std::ptrdiff_t>(x.size()) - 1; i >= 0; --i) {
        sum += x[static_cast<std::size_t>(i)];
        output[static_cast<std::size_t>(i)] = sum;
    }
}
