#include <omp.h>
#include <algorithm>

/*
 * Compute the maximum degree of an undirected graph whose adjacency matrix
 * is given as a flat 1‑D vector A in row‑major order.
 *
 * The implementation uses OpenMP parallelism and a reduction to compute
 * the sum of each row efficiently.
 */
int maxDegree(const std::vector<int>& A, size_t N)
{
    // Use a pointer for faster access
    const int* ptr = A.data();
    int maxDeg = 0;

    // Parallelize the outer loop over rows with a reduction on the maximum
    #pragma omp parallel for reduction(max:maxDeg) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        int deg = 0;
        const int* row = ptr + i * N;
        // Unroll the inner loop for a modest speedup
        for (size_t j = 0; j < N; j += 8) {
            deg += row[j];
            if (j + 1 < N) deg += row[j + 1];
            if (j + 2 < N) deg += row[j + 2];
            if (j + 3 < N) deg += row[j + 3];
            if (j + 4 < N) deg += row[j + 4];
            if (j + 5 < N) deg += row[j + 5];
            if (j + 6 < N) deg += row[j + 6];
            if (j + 7 < N) deg += row[j + 7];
        }
        maxDeg = std::max(maxDeg, deg);
    }
    return maxDeg;
}
