```cpp
#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

/* Count the number of Cartesian points in each quadrant.
   The vector `points` contains a list of `Point` objects.
   Store the counts in `bins` (order: Q1, Q2, Q3, Q4).
   The function is thread‑safe and preserves the exact behavior
   of the original serial implementation. */
inline void countQuadrants(const std::vector<Point>& points, std::array<std::size_t, 4>& bins) {
    // Ensure bins are zeroed before accumulation
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Use OpenMP parallel for with reduction on a temporary array
    constexpr int Q = 4;
    std::array<std::size_t, Q> local_bins;

#pragma omp parallel
    {
        // Each thread starts with zeroed local counters
        for (auto& v : local_bins) v = 0;

#pragma omp for nowait
        for (std::size_t i = 0; i < points.size(); ++i) {
            const auto& p = points[i];
            if      (p.x >= 0 && p.y >= 0) local_bins[0] += 1;
            else if (p.x <  0 && p.y >= 0) local_bins[1] += 1;
            else if (p.x <  0 && p.y <  0) local_bins[2] += 1;
            else if (p.x >= 0 && p.y <  0) local_bins[3] += 1;
        }

        // Merge local bins into global bins atomically
#pragma omp critical
        {
            for (int q = 0; q < Q; ++q) bins[q] += local_bins[q];
        }
    }
}
