#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct Element {
    std::size_t index;
    double value;
};

/*
 * Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the existing array z.
 *
 * To preserve the exact behavior of the original sequential algorithm,
 * we perform two independent parallel passes over x and y, adding the
 * contributions atomically. This guarantees the same final values
 * as the single‑threaded merge while taking advantage of multiple cores.
 */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double>& z) {

    // Add contributions from x: z[idx] += alpha * value
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        std::size_t idx = x[i].index;
        double val = alpha * x[i].value;
        // atomic update to avoid data races
        #pragma omp atomic
        z[idx] += val;
    }

    // Add contributions from y: z[idx] += value
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < y.size(); ++i) {
        std::size_t idx = y[i].index;
        double val = y[i].value;
        #pragma omp atomic
        z[idx] += val;
    }
}
