18_graph_count_components:
```cpp
#pragma once
#include <vector>
#include <cstdint>
#include <cstring>

/*------------------------------------------------------------------------
  Fast connected‑component counter for an undirected graph given as a
  row‑major NxN adjacency matrix.
  -----------------------------------------------------------------------*/

inline void dfs_stack(const int* data, std::size_t N,
                      std::size_t start, std::vector<char>& vis)
{
    // explicit stack to avoid recursion overhead
    std::vector<std::size_t> stack;
    stack.reserve(N);
    stack.push_back(start);
    vis[start] = 1;

    while (!stack.empty()) {
        std::size_t node = stack.back();
        stack.pop_back();

        const std::size_t base = node * N;
        for (std::size_t i = 0; i < N; ++i) {
            if (data[base + i] == 1 && !vis[i]) {
                vis[i] = 1;
                stack.push_back(i);
            }
        }
    }
}

/* count the number of connected components in the undirected graph
   defined by the adjacency matrix A.  A is stored in row‑major
   order.  The function preserves the exact behaviour of the original
   implementation. */
int componentCount(std::vector<int> const& A, std::size_t N) {
    if (N == 0) return 0;

    const int* data = A.data();
    std::vector<char> visited(N, 0);
    int count = 0;

    for (std::size_t i = 0; i < N; ++i) {
        if (!visited[i]) {
            dfs_stack(data, N, i, visited);
            ++count;
        }
    }
    return count;
}
