```cpp
#pragma once
#include <vector>
#include <limits>

/* Return the length of the shortest path from source to dest
   in an undirected graph given by adjacency matrix A.
   Matrix A is stored in row‑major order and the graph is connected. */
int shortestPathLength(std::vector<int> const& A, size_t N, int source, int dest) {
    // Quick return for trivial case
    if (source == dest) return 0;

    // Mark array stored as char for minimal cache footprint
    std::vector<char> visited(N, 0);
    visited[source] = 1;

    // Simple circular queue stored in a pre‑allocated array
    std::vector<int> q(N);
    std::vector<int> qd(N);  // distance parallel to q
    size_t qhead = 0, qtail = 0;

    q[qtail] = source;
    qd[qtail] = 0;
    ++qtail;

    while (qhead != qtail) {
        int cur   = q[qhead];
        int dist  = qd[qhead];
        ++qhead;

        // traverse all possible neighbours
        const int* row = &A[cur * N];
        for (size_t n = 0; n < N; ++n) {
            if (row[n] && !visited[n]) {
                if (static_cast<int>(n) == dest) {
                    return dist + 1;
                }
                visited[n] = 1;
                q[qtail]   = static_cast<int>(n);
                qd[qtail]  = dist + 1;
                ++qtail;
            }
        }
    }

    // Should never happen for a connected graph
    return std::numeric_limits<int>::max();
}
