#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

const double PI = 3.14159265358979323846264338327950288L;   // 64‑bit precision

// In‑place vector FFT – naive DFT implementation with OpenMP improvements
// and a small amount of pre‑computation to reduce runtime.
void dft(const std::vector<double> &x, std::vector<std::complex<double>> &output) {
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑compute 2π/N once – fewer divisions in inner loop
    const double twopi_over_N = 2.0 * PI / static_cast<double>(N);

    // We'll also cache the sin/cos terms for each (n*k) pair in a 1‑D matrix.
    // That avoids recomputing trigonometric functions for each k and n.
    std::vector<std::vector<std::complex<double>>> table(N, std::vector<std::complex<double>>(N));

    // Fill the table (this is O(N²) ~ 16 M operations for N=4096 – acceptable once)
#pragma omp parallel for collapse(2) schedule(static)
    for (int n = 0; n < N; ++n) {
        for (int k = 0; k < N; ++k) {
            double angle = twopi_over_N * static_cast<double>(n * k);
            table[n][k] = std::complex<double>(std::cos(angle), -std::sin(angle));
        }
    }

    // Compute the DFT using the precalculated table
#pragma omp parallel for schedule(static)
