/* Optimised sparse‑sparse matrix multiplication.
 *
 * A : MxK sparse matrix in COO format.
 * X : KxN sparse matrix in COO format.
 * Y : dense MxN matrix (row major) – must be provided with size M*N.
 *
 * The algorithm builds a mapping from the row index of X to all its
 * non‑zero entries so that the inner loop only visits compatible pairs.
 * The outer loop over A is parallelised with OpenMP.  Each thread writes
 * into a private buffer which is accumulated into the global Y at the
 * end.   This eliminates the costly cache thrashing caused by
 * frequent concurrent updates to Y.
 */
void spmm(const std::vector<COOElement>& A,
          const std::vector<COOElement>& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    /* Build a mapping from X.row -> list of (col, value) */
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> x_map;
    x_map.reserve(X.size()*2);
    for (const auto& x : X) {
        x_map[x.row].push_back({x.column, x.value});
    }

    /* Thread‑private buffers to avoid atomic increments */
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> thread_acc(nthreads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        std::vector<double>& local = thread_acc[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < A.size(); ++i) {
            const auto& a = A[i];
            auto it = x_map.find(a.column);
            if (it == x_map.end()) continue;          // no compatible X entries

            const auto& vec = it->second;
            double a_val = a.value;
            size_t row_offset = a.row * N;

            for (const auto& pair : vec) {
                local[row_offset + pair.first] += a_val * pair.second;
            }
        }
    }

    /* Accumulate per‑thread results into Y */
    for (int t = 0; t < nthreads; ++t) {
        const auto& local = thread_acc[t];
        for (size_t i = 0; i < M * N; ++i) {
            Y[i] += local[i];
        }
    }
}
