#pragma once
#include <vector>
#include <cstddef>

struct COOElement
{
    std::size_t row, column;
    double value;
};

// LU factorization of a sparse matrix A (COO) into L and U (row‑major)
// L is unit lower triangular. All arrays are stored in linear order.
inline void luFactorize(const std::vector<COOElement> &A,
                        std::vector<double> &L,
                        std::vector<double> &U,
                        std::size_t N)
{
    // Allocate flat matrix A in row‑major format
    std::vector<double> flatA(N * N, 0.0);

    // Build the dense matrix from COO representation
#pragma omp parallel for schedule (static,64) nowait
    for (std::size_t idx = 0; idx < A.size(); ++idx)
    {
        const auto &e = A[idx];
        flatA[e.row * N + e.column] = e.value;
    }

    // Initialize L and U
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    // Classical Doolittle algorithm (no pivoting)
    for (std::size_t i = 0; i < N; ++i)
    {
        // Upper part
        for (std::size_t j = i; j < N; ++j)
        {
            double sum = flatA[i * N + j];
            for (std::size_t k = 0; k < i; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = sum;
        }

        // Lower part
        for (std::size_t j = 0; j < i; ++j)
        {
            double sum = flatA[i * N + j];
            for (std::size_t k = 0; k < j; ++k)
                sum -= L[i * N + k] * U[k * N + j];
            L[i * N + j] = sum / U[j * N + j];
        }

        // Unit diagonal
        L[i * N + i] = 1.0;
    }
}
```

