// Return the distance between the closest two elements in the vector x.
// Example:
//   input: [7, 3, 9, 12, 31, 1]
//   output: 2
double closestPair(const std::vector<double>& x) {
    // The vector needs to have at least two elements
    if (x.size() < 2) {
        return 0.0;
    }

    // Make a copy and sort it – sorting is O(n log n) and guarantees that
    // the closest pair must be adjacent in the sorted order.
    std::vector<double> sorted(x);
    std::sort(sorted.begin(), sorted.end());

    // Scan adjacent pairs to find the minimum difference.
    double minDist = std::numeric_limits<double>::max();
    for (size_t i = 1; i < sorted.size(); ++i) {
        const double d = sorted[i] - sorted[i - 1];  // non‑negative
        if (d < minDist) {
            minDist = d;
            if (minDist == 0.0) { // cannot get any smaller
                break;
            }
        }
    }

    return minDist;
}
