#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>
#include <cstring>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Exact behavior is preserved. */
void solveLinearSystem(const std::vector<COOElement> &A,
                       const std::vector<double>   &b,
                       std::vector<double>         &x,
                       size_t                       N)
{
    /* Allocate dense matrix (row major). Use a single contiguous buffer
       for better cache behaviour. */
    std::vector<double> mat(N * N, 0.0);
    auto ELEM = [N](size_t r, size_t c){ return r * N + c; };

    /* Fill matrix with COO values */
    for (const auto& el : A)
        mat[ELEM(el.row, el.column)] = el.value;

    /* b copy (we will overwrite it during elimination) */
    std::vector<double> b_copy = b;

    /* Forward elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* ---- Pivot search (parallel) ---- */
        size_t maxRow = i;
        double maxVal = std::abs(mat[ELEM(i, i)]);
        #pragma omp parallel
        {
            size_t localRow = i;
            double localMax = maxVal;
            #pragma omp for nowait
            for (size_t k = i + 1; k < N; ++k) {
                double val = std::abs(mat[ELEM(k, i)]);
                if (val > localMax) {
                    localMax = val;
                    localRow = k;
                }
            }
            #pragma omp critical
            {
                if (localMax > maxVal) {
                    maxVal = localMax;
                    maxRow = localRow;
                }
            }
        }

        /* ---- Row swap with maxRow ---- */
        if (maxRow != i) {
            for (size_t c = i; c < N; ++c)
                std::swap(mat[ELEM(maxRow, c)], mat[ELEM(i, c)]);
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* ---- Eliminate below rows (parallel) ---- */
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double c = -mat[ELEM(k, i)] / mat[ELEM(i, i)];
            if (c == 0.0) continue;                   // skip zero multiplier
            /* Set diagonal to zero explicitly */
            mat[ELEM(k, i)] = 0.0;
            for (size_t j = i + 1; j < N; ++j)
                mat[ELEM(k, j)] += c * mat[ELEM(i, j)];
            b_copy[k] += c * b_copy[i];
        }
    }

    /* ---- Back substitution ---- */
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        for (int j = i + 1; j < static_cast<int>(N); ++j)
            sum -= mat[ELEM(i, j)] * x[j];
        x[i] = sum / mat[ELEM(i, i)];
    }
}
