/*
 * Grid cell XOR: Each cell becomes 1 iff exactly one of its
 * orthogonal neighbours (up, down, left, right) is 1. Input and
 * output are N×N grids stored in row‑major order.
 *
 * The function is fully parallelised with OpenMP and uses
 * pointer arithmetic to avoid vector indexing overhead.
 */
inline void cellsXOR(const std::vector<int> &input,
                     std::vector<int> &output,
                     std::size_t N) noexcept
{
    const std::size_t NSq = N * N;

    /* Ensure output vector has correct size */
    if (output.size() != NSq)
        output.resize(NSq);

    /* Cast to raw pointers for speed. GCC will honour the
       const/volatile qualifiers and apply -fno-strict-aliasing. */
    const int  *in   = input.data();
    int        *out  = output.data();

    /* Parallel outer loop: each thread processes a distinct row */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t idx   = i * N;          // base index of row i
        const bool        top   = (i > 0);
        const bool        bottom= (i + 1 < N);
        for (std::size_t j = 0; j < N; ++j) {
            uint8_t count = 0;                    // count fits in 4 bits

            /* up */
            if (top && in[idx - N + j] == 1) ++count;
            /* down */
            if (bottom && in[idx + N + j] == 1) ++count;
            /* left */
            if (j > 0 && in[idx + j - 1] == 1) ++count;
            /* right */
            if (j + 1 < N && in[idx + j + 1] == 1) ++count;

            out[idx + j] = (count == 1) ? 1 : 0;
        }
    }
}
