/* Return the area of the smallest triangle that can be formed by any 3 points.
   Uses OpenMP to parallelise the O(n³) search while preserving exact arithmetic
   behaviour of the original implementation.
*/
double smallestArea(std::vector<Point> const& points)
{
    const std::size_t n = points.size();
    if (n < 3)
        return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* Parallelise the two outer loops.
       The innermost loop is trivial and will be executed by the thread
       that owns the current `i` and `j` pair.  The standard reduction
       clause guarantees that the final value of minArea is the global
       minimum.                                                */
#pragma omp parallel for collapse(2) schedule(dynamic) reduction(min : minArea)
    for (std::size_t i = 0; i < n - 2; ++i)
    {
        for (std::size_t j = i + 1; j < n - 1; ++j)
        {
            for (std::size_t k = j + 1; k < n; ++k)
            {
                double area = triArea(points[i], points[j], points[k]);
                if (area < minArea)
                    minArea = area;
            }
        }
    }

    return minArea;
}
