       we perform a parallel inclusive scan implementation that behaves
       identically.  We use a two–pass algorithm:
         1. Each thread computes a local prefix sum on its chunk, storing
            the last element of the chunk as the chunk total.
         2. Prefix sums of the chunk totals are accumulated serially
            (this serial step is tiny compared to the main work on large
            vectors).
         3. Each thread adds its corresponding offset to all elements
            in its chunk.                                            */

    /* Number of OpenMP threads (clamp to at least 1). */
    const int num_threads = std::max(1, omp_get_max_threads());

    /* Compute chunk boundaries. */
    std::vector<std::size_t> chunk_starts(num_threads + 1, 0);
    const std::size_t base = n / num_threads;
    const std::size_t rem  = n % num_threads;
    std::size_t pos = 0;
    for (int i = 0; i < num_threads; ++i) {
        chunk_starts[i] = pos;
        pos += base + (i < rem ? 1 : 0);
    }
    chunk_starts[num_threads] = n;          // one past the end

    /* Parallel local scans.  We also store each chunk's total in
       `chunk_totals` for the serial pass. */
    std::vector<int64_t> chunk_totals(num_threads, 0);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = chunk_starts[tid];
        const std::size_t end   = chunk_starts[tid + 1];

        if (start < end) {
            int64_t acc = 0;
            for (std::size_t i = start; i < end; ++i) {
                acc += x[i];
                output[i] = acc;               // local prefix
            }
            chunk_totals[tid] = acc;            // total of this chunk
        }
    }

    /* Serial accumulation of chunk totals to get offsets. */
    std::vector<int64_t> chunk_offsets(num_threads, 0);
    if (!chunk_totals.empty()) {
        int64_t sum = 0;
        for (int i = 0; i < num_threads; ++i) {
            chunk_offsets[i] = sum;
            sum += chunk_totals[i];
        }
        /* Add the offsets to each element of the owning chunk. */
        #pragma omp parallel
        {
            const int tid = omp_get_thread_num();
            const std::size_t start = chunk_starts[tid];
            const std::size_t end   = chunk_starts[tid + 1];
            const int64_t off = chunk_offsets[tid];
            for (std::size_t i = start; i < end; ++i) {
                output[i] += off;
            }
        }
    }
}
