#pragma once
#include <vector>
#include <algorithm>

struct Point
{
    double x, y;
};

/* Compute the convex hull of a set of points using the boundary
 * algorithm (Monotone chain / Graham scan). The result is stored
 * in `hull`. The algorithm keeps the order counter‑clockwise
 * starting from the leftmost point. */
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    std::vector<Point> sorted = points;          // copy for sorting
    sorted.reserve(n);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& p1, const Point& p2)
              {
                  return p1.x < p2.x || (p1.x == p2.x && p1.y < p2.y);
              });

    // Allocate maximum possible size (2*n) for the hull
    std::vector<Point> temp;
    temp.reserve(2 * n);
    temp.resize(n); // space for lower hull
    size_t k = 0;

    /* Build lower hull */
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(temp[k - 2], temp[k - 1], sorted[i]) <= 0)
            --k;
        temp[k++] = sorted[i];
    }

    /* Build upper hull */
    size_t t = k + 1;   // starting index for upper part
    for (size_t i = n; i-- > 0;)
    {
        while (k >= t && cross(temp[k - 2], temp[k - 1], sorted[i]) <= 0)
            --k;
        temp[k++] = sorted[i];
    }

    temp.resize(k - 1); // last point would be same as first
    hull = std::move(temp);
}
