static constexpr std::size_t BLOCK = 64;   // block size tuned for L1 cache

inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 std::size_t M, std::size_t N) {

    // guard against zero-sized matrices
    if (M == 0 || N == 0) return;

    // parallelize over rows of A
    #pragma omp parallel for schedule(static, BLOCK) collapse(1)
    for (std::size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        const std::size_t idx = i * N;

        // vectorized inner loop, unrolled 4x
        std::size_t j = 0;
        for (; j + 3 < N; j += 4) {
            sum += A[idx + j]     * x[j];
            sum += A[idx + j + 1] * x[j + 1];
            sum += A[idx + j + 2] * x[j + 2];
            sum += A[idx + j + 3] * x[j + 3];
        }
        for (; j < N; ++j) {
            sum += A[idx + j] * x[j];
        }
        y[i] = sum;
    }
