/* Compute one iteration of a 5‑point 2‑D Jacobi stencil.  
   The implementation is fully parallelized with OpenMP and
   removes branch overhead by using a flat index loop.
   Behaviour is identical to the reference implementation. */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double>& output,
                     std::size_t N)
{
    const std::size_t total = N * N;
    const double div5 = 1.0 / 5.0;

    /* Prefer a flat loop to reduce branch mis‑prediction cost.
       The index is split into row (i) and column (j) on the fly.
       OpenMP parallelises the work across all available threads. */
    #pragma omp parallel for schedule(static)
    for(std::size_t idx = 0; idx < total; ++idx)
    {
        const std::size_t i = idx / N;          // row
        const std::size_t j = idx % N;          // column
        const std::size_t base = i * N;

        double sum = input[base + j];           // center

        if (i > 0)          sum += input[base - N + j];   // north
        if (i + 1 < N)      sum += input[base + N + j];   // south
        if (j > 0)          sum += input[base + j - 1];   // west
        if (j + 1 < N)      sum += input[base + j + 1];   // east

        output[idx] = sum * div5;
    }
}
