#   define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------------------
// 8‑stage iterative radix‑2 Cooley‑Tukey FFT with OpenMP parallelism
// ---------------------------------------------------------------------------

void fft(const std::vector<std::complex<double>>& x,
         std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output = x;                          // work in place

    // ---------- 1. Pre‑compute twiddle factors ----------
    const double two_pi = 2.0 * M_PI;
    std::vector<std::complex<double>> twiddles(N >> 1);
    for (std::size_t i = 0; i < twiddles.size(); ++i) {
        const double angle = -two_pi * i / static_cast<double>(N);
        twiddles[i] = std::polar(1.0, angle);   // exp(-j*2πk/N)
    }

    // ---------- 2. Butterfly stages ----------
    //  bit‑reversal is done afterwards
    for (std::size_t stage = 1, half = 1; stage <= std::size_t(std::log2(N)); ++stage, half <<= 1) {
        const std::size_t full = half << 1;
        const std::size_t stride = N / full;

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += full) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::size_t idx1 = i + j;
                const std::size_t idx2 = idx1 + half;
                const std::complex<double> t = output[idx1] - output[idx2];
                output[idx1] += output[idx2];
                output[idx2] = t * twiddles[j * stride];
            }
        }
    }

    // ---------- 3. Bit reversal ----------
    const std::size_t m = std::size_t(std::log2(N));
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = i;
        j = ((j & 0x55555555u) << 1) | ((j & 0xaaaaaaaau) >> 1);
        j = ((j & 0x33333333u) << 2) | ((j & 0xccccccccu) >> 2);
        j = ((j & 0x0f0f0f0fu) << 4) | ((j & 0xf0f0f0f0u) >> 4);
        j = ((j & 0x00ff00ffu) << 8) | ((j & 0xff00ff00u) >> 8);
        j = (j << 16) | (j >> 16);
        j >>= (32 - m);

        if (j > i) {
            std::swap(output[i], output[j]);
        }
    }
}
