    }

    struct MinInfo {
        double value;
        size_t index;
        MinInfo() : value(std::numeric_limits<double>::infinity()), index(0) {}
    } global{};

    // Parallel reduction (custom) to find minimum absolute difference
    #pragma omp parallel
    {
        MinInfo local{};
