struct Point {
    double x, y;
};

static inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

static inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/*
 * Compute the perimeter of the convex hull of the given points.
 * The implementation follows the Andrew monotone chain algorithm,
 * but is heavily tuned for speed on an 8‑thread x86‑64 machine.
 */
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3)
        return 0.0;

    // copy to a temporary vector for sorting
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // Allocate hull array large enough (at most 2*n)
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], pts[i]) <= 0.0)
            --k;
        hull[k++] = pts[i];
    }

    // Build upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n - 1; i > 0; --i) {
        while (k >= t && cross(hull[k - 2], hull[k - 1], pts[i - 1]) <= 0.0)
            --k;
        hull[k++] = pts[i - 1];
    }

    // The last point of the hull is the same as the first one;
    // shrink the array to k-1 points.
    hull.resize(k - 1);

    // Parallel sum of edge lengths.
    double perimeter = 0.0;
    #pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i < hull.size(); ++i) {
        const Point& a = hull[i];
        const Point& b = hull[(i + 1) % hull.size()];
        perimeter += dist(a, b);
    }

    return perimeter;
}
