inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output, std::size_t N) {
    // Avoid bounds checks by using raw pointers
    const int *restrict in  = input.data();
          int *restrict out = output.data();
    const std::size_t stride = N;

    // Parallelise the outer loop with OpenMP
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const std::size_t iN  = i * stride;
        const std::size_t im1 = (i > 0) ? (i - 1) * stride : SIZE_MAX;
        const std::size_t ip1 = (i + 1 < N) ? (i + 1) * stride : SIZE_MAX;

        for (std::size_t j = 0; j < N; ++j) {
            const std::size_t idx = iN + j;
            int sum = 0;

            // North
            if (im1 != SIZE_MAX) sum += in[im1 + j];
            // South
            if (ip1 != SIZE_MAX) sum += in[ip1 + j];
            // West
            if (j > 0)            sum += in[idx - 1];
            // East
            if (j + 1 < N)        sum += in[idx + 1];
            // NW
            if (im1 != SIZE_MAX && j > 0)            sum += in[im1 + j - 1];
            // NE
            if (im1 != SIZE_MAX && j + 1 < N)        sum += in[im1 + j + 1];
            // SW
            if (ip1 != SIZE_MAX && j > 0)            sum += in[ip1 + j - 1];
            // SE
            if (ip1 != SIZE_MAX && j + 1 < N)        sum += in[ip1 + j + 1];

            const int cur = in[idx];
            if (cur == 1) {
                out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                out[idx] = (sum == 3) ? 1 : 0;
            }
