/* Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
   This implementation uses a parallel prefix (scan) algorithm that scales with
   the number of available threads while preserving the exact behaviour of the
   original sequential inclusive_scan version. */
void partialMinimums(std::vector<float> &x)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    const int max_threads = omp_get_max_threads();
    const std::size_t block_size = (n + max_threads - 1) / max_threads;

    /* 1. Compute the minimum for each block in parallel. */
    std::vector<float> block_min(max_threads, std::numeric_limits<float>::max());

    #pragma omp parallel
    {
        const int tid  = omp_get_thread_num();
        const std::size_t start = tid * block_size;
        const std::size_t end   = std::min(n, start + block_size);

        float local_min = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i)
            local_min = std::min(local_min, x[i]);

        block_min[tid] = local_min;
    }

    /* 2. Serially compute the prefix minimum over the block minima. */
    std::vector<float> prefix_min(max_threads);
    float acc = std::numeric_limits<float>::max();
    for (int i = 0; i < max_threads; ++i) {
        acc = std::min(acc, block_min[i]);
        prefix_min[i] = acc;
    }

    /* 3. Update each block with its starting prefix minimum. */
    #pragma omp parallel
    {
        const int tid  = omp_get_thread_num();
        const std::size_t start = tid * block_size;
        const std::size_t end   = std::min(n, start + block_size);

        float cur = prefix_min[tid];
        for (std::size_t i = start; i < end; ++i) {
            cur = std::min(cur, x[i]);
            x[i] = cur;
        }
    }
}
