/*
 *  In‑place radix‑2 Cooley‑Tukey FFT (complex‑to‑complex).
 *  Mirrors the functional behaviour of the original implementation:
 *      - the input vector `x` is not modified,
 *      - the result is written into the pre‑allocated real vector `r`
 *        and imaginary vector `i`.
 *
 *  Optimisations:
 *      - All twiddle factors are pre‑computed in a flat array.
 *      - Bit‑reverse indices are computed once and reused.
 *      - Inner work‑sharing OpenMP pragmas accelerate the transform for
 *        large vectors (8 threads, x86‑64, GCC‑O2, -fopenmp).
 *
 *  Complexity:   O(N log N)
 *  Assumptions:  |x| is a power of two.
 */
void fft(const std::vector<std::complex<double>>& x,
         std::vector<double>& r,
         std::vector<double>& i)
{
    constexpr double PI = 3.141592653589793238462643383279502884L;
    const std::size_t N = x.size();
    r.resize(N, 0.0);
    i.resize(N, 0.0);

    // Work array – copy of the input
    std::vector<std::complex<double>> a(x);

    // -------------------------------------------------------------
    // 1) Pre‑compute twiddle factors: W_N^k = exp(-2πi*k/N)
    //    Stored contiguously: w[k] = exp(-2πi*k/N)
    // -------------------------------------------------------------
    std::vector<std::complex<double>> w(N >> 1);
    for (std::size_t k = 0; k < (N >> 1); ++k) {
        double angle = -2.0 * PI * k / static_cast<double>(N);
        w[k] = std::polar(1.0, angle);
    }

    // -------------------------------------------------------------
    // 2) Cooley–Tukey decimation‑in‑time
    //    The butterfly stages are performed iteratively.
    // -------------------------------------------------------------
    std::size_t half_size = 1;
    while (half_size < N) {
        std::size_t full_size = half_size << 1;
        std::size_t step     = N / full_size;          // offset for twiddle selection

        // Parallelise over the starting points of the butterflies
        #pragma omp parallel for schedule(static)
        for (std::size_t start = 0; start < N; start += full_size) {
            for (std::size_t j = 0; j < half_size; ++j) {
                std::size_t idx1   = start + j;
                std::size_t idx2   = start + j + half_size;
                std::complex<double> t = a[idx2] * w[j * step];
                a[idx2] = a[idx1] - t;
                a[idx1] += t;
            }
        }
        half_size = full_size;
    }

    // -------------------------------------------------------------
    // 3) Bit‑reversal permutation (in‑place)
    // -------------------------------------------------------------
    //  Pre‑compute bit‑reversed indices to avoid recomputation.
    const std::size_t bits = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t x = i, y = 0;
        for (std::size_t j = 0; j < bits; ++j) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[i] = y;
    }

    for (std::size_t j = 0; j < N; ++j) {
        std::size_t k = rev[j];
        if (k > j) {
            std::swap(a[j], a[k]);
        }
    }

    // -------------------------------------------------------------
    // 4) Split into real and imaginary parts
    // -------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = a[j].real();
        i[j] = a[j].imag();
    }
}
