/* Return true if the vector x contains the value `target`. Return false otherwise.
   Examples:
   input: x=[1, 8, 2, 6, 4, 6], target=3
   output: false
   input: x=[1, 8, 2, 6, 4, 6], target=8
   output: true
*/
bool contains(const std::vector<int>& x, int target) {
    // Avoid any extra overhead by using a raw pointer and loop unrolling.
    const int* ptr = x.data();
    const std::size_t n = x.size();
    std::size_t i = 0;

    // Process 8 integers per iteration for cache friendliness.
    for (; i + 7 < n; i += 8) {
        if (ptr[i]   == target) return true;
        if (ptr[i+1] == target) return true;
        if (ptr[i+2] == target) return true;
        if (ptr[i+3] == target) return true;
        if (ptr[i+4] == target) return true;
        if (ptr[i+5] == target) return true;
        if (ptr[i+6] == target) return true;
        if (ptr[i+7] == target) return true;
    }

    // Handle remaining elements
    for (; i < n; ++i) {
        if (ptr[i] == target) return true;
    }
    return false;
}
