#include <omp.h>

struct Point
{
    double x, y;
};

// Return squared distance without calling sqrt/ pow
inline double sqr(double v) { return v * v; }
inline double dist2(const Point &a, const Point &b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// O(n log n) closest pair using divide‑and‑conquer
static double closest_pair_recursive(std::vector<Point> &px, std::vector<Point> &py, size_t l, size_t r)
{
    size_t n = r - l;
    if (n <= 3) {                // brute‑force
        double best = std::numeric_limits<double>::infinity();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                best = std::min(best, dist2(px[i], px[j]));
        std::sort(px.begin() + l, px.begin() + r, [](const Point &a, const Point &b){ return a.y < b.y; });
        return best;
    }

    size_t mid = l + n / 2;
    double midx = px[mid].x;

    // Partition py into left/right
    std::vector<Point> pyl;
    std::vector<Point> pyr;
    pyl.reserve(mid - l);
    pyr.reserve(r - mid);
    for (size_t i = l; i < r; ++i)
    {
        if (py[i].x <= midx) pyl.push_back(py[i]);
        else pyr.push_back(py[i]);
    }

    double leftBest, rightBest;
#pragma omp task shared(px, py) untied if(n > 5000)
    leftBest = closest_pair_recursive(px, pyl, l, mid);
#pragma omp task shared(px, py) untied if(n > 5000)
    rightBest = closest_pair_recursive(px, pyr, mid, r);
#pragma omp taskwait

    double best = std::min(leftBest, rightBest);

    // Merge py sorted by y
    std::merge(pyl.begin(), pyl.end(),
               pyr.begin(), pyr.end(),
               py.begin() + l, [](const Point &a, const Point &b){ return a.y < b.y; });

    // Build strip
    std::vector<Point> strip;
    strip.reserve(n);
    for (size_t i = l; i < r; ++i)
        if (std::abs(py[i].x - midx) < std::sqrt(best))
            strip.push_back(py[i]);

    // Check strip: at most 7 neighbours
    for (size_t i = 0; i < strip.size(); ++i)
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < std::sqrt(best); ++j)
            best = std::min(best, dist2(strip[i], strip[j]));

    return best;
}

// Public interface matching original signature
double closestPair(std::vector<Point> const& points)
{
    if (points.size() < 2)
        return 0.0;

    std::vector<Point> px = points;          // copy for sorting by x
    std::vector<Point> py = points;
    std::sort(px.begin(), px.end(), [](const Point &a, const Point &b){ return a.x < b.x; });
    std::sort(py.begin(), py.end(), [](const Point &a, const Point &b){ return a.y < b.y; });

    double bestSq;
#pragma omp parallel
    {
#pragma omp single
        bestSq = closest_pair_recursive(px, py, 0, px.size());
    }

    return std::sqrt(bestSq);
}
