void sortIgnoreZero(std::vector<int> &x) {
    // First pass – count non‑zero elements so we can reserve the required
    // space and avoid re‑allocations during the copy.
    std::size_t nzCnt = 0;
    for (const int v : x)
        if (v != 0)
            ++nzCnt;

    if (nzCnt == 0) /* nothing to do */
        return;

    // Copy the non‑zero values into a separate buffer.
    std::vector<int> buf;
    buf.reserve(nzCnt);          // pre‑size to avoid re‑allocation
    for (int v : x)
        if (v != 0)
            buf.push_back(v);

    // Sort the non‑zero values.
    std::sort(buf.begin(), buf.end());

    // Second pass – write the sorted non‑zeros back into the original vector
    // while keeping the zero positions unchanged.
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            x[i] = buf[idx++];
        }
    }
}
