#pragma once
#include <cmath>
#include <vector>
#include <complex>
#include <algorithm>
#include <cstddef>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// In‑place, iterative, radix‑2 Cooley‑Tukey FFT.
// The algorithm follows the reference implementation but
// parallelises the innermost butterfly loop.
inline void fft_helper_inplace(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N <= 1) return;

    std::size_t k = N;
    std::size_t n;
    double thetaT = 3.14159265358979323846264338328L / static_cast<double>(N);
    std::complex<double> phiT  = std::complex<double>(std::cos(thetaT), -std::sin(thetaT));
    std::complex<double> T;

    while (k > 1) {
        n = k;
        k >>= 1;
        phiT *= phiT;
        T = 1.0L;

        // Parallel butterflies for a given "stage" k
        #pragma omp parallel for schedule(static)
        for (std::size_t l = 0; l < k; ++l) {
            for (std::size_t a = l; a < N; a += n) {
                std::size_t b = a + k;
                std::complex<double> t = x[a] - x[b];
                x[a] += x[b];
                x[b] = t * T;
            }
        }
        T *= phiT;
    }

    // Bit‑reversal permutation
    const std::size_t m = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    for (std::size_t a = 0; a < N; ++a) {
        std::size_t b = a;
        b = (((b & 0xaaaaaaaa) >> 1) | ((b & 0x55555555) << 1));
        b = (((b & 0xcccccccc) >> 2) | ((b & 0x33333333) << 2));
        b = (((b & 0xf0f0f0f0) >> 4) | ((b & 0x0f0f0f0f) << 4));
        b = (((b & 0xff00ff00) >> 8) | ((b & 0x00ff00ff) << 8));
        b = ((b >> 16) | (b << 16)) >> (32 - m);
        if (b > a) std::swap(x[a], x[b]);
    }
}

// Inverse FFT using the conjugate‑transpose trick.
inline void ifft(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    // Conjugate all elements
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // Forward FFT
    fft_helper_inplace(x);

    // Conjugate again
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // Scale
    const double invN = 1.0 / static_cast<double>(N);
    std::transform(x.begin(), x.end(), x.begin(),
                   [invN](const std::complex<double>& v){ return v * invN; });
}
