#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/// Solve the linear system Ax = b for x.
/// A is an NxN matrix in row‑major.  x and b have N elements.
/// If a zero pivot is encountered the function returns without modifying x.
/// The algorithm is a straightforward Gaussian elimination followed by back‑substitution.
/// All costly operations are performed on raw pointers and inner loops are
/// parallelised with OpenMP to take advantage of the 8‑thread CPU.
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       std::size_t N)
{
    // Copy input data so we can freely modify it
    std::vector<double> A_copy = A;
    std::vector<double> b_copy = b;

    double const *Arow;    // pointer helpers
    double *Acol;
    double *bptr = b_copy.data();

    // Gaussian elimination with row‑wise parallelisation
    for (std::size_t i = 0; i < N - 1; ++i) {
        double pivot = A_copy[i * N + i];
        if (pivot == 0.0)          // preserve original behaviour
            return;

        // Parallel eliminate rows below the pivot
        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            double *row_j = &A_copy[j * N];
            double *row_i = &A_copy[i * N];
            double factor = row_j[i] / pivot;

            // Update row j
            for (std::size_t k = i; k < N; ++k)
                row_j[k] -= factor * row_i[k];

            bptr[j] -= factor * bptr[i];
        }
    }

    // Back substitution (sequential)
    for (int64_t i = static_cast<int64_t>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        double const *row_i = &A_copy[i * N];
        for (std::size_t j = i + 1; j < N; ++j)
            sum += row_i[j] * x[j];
        x[i] = (b_copy[i] - sum) / row_i[i];
    }
}
