#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
   Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
   The matrices are stored in row-major order.
*/
inline void gemm(const std::vector<double>& A, const std::vector<double>& B,
                 std::vector<double>& C, size_t M, size_t K, size_t N)
{
    const double* a_ptr = A.data();
    const double* b_ptr = B.data();
    double*       c_ptr = C.data();

    /* Parallelize the outermost i‑loop.  
       The inner loops are kept inside to keep the per‑thread cache locality. */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        double*  c_row = c_ptr + i * N;
        size_t   offsetA = i * K;

        for (size_t k = 0; k < K; ++k) {
            double a_val = a_ptr[offsetA + k];
            const double* b_row = b_ptr + k * N;

            /* Unroll the innermost j‑loop for better vectorisation. */
            size_t j = 0;
            for (; j + 7 < N; j += 8) {
                double c0 = c_row[j]   + a_val * b_row[j];
                double c1 = c_row[j+1] + a_val * b_row[j+1];
                double c2 = c_row[j+2] + a_val * b_row[j+2];
                double c3 = c_row[j+3] + a_val * b_row[j+3];
                double c4 = c_row[j+4] + a_val * b_row[j+4];
                double c5 = c_row[j+5] + a_val * b_row[j+5];
                double c6 = c_row[j+6] + a_val * b_row[j+6];
                double c7 = c_row[j+7] + a_val * b_row[j+7];

                c_row[j]   = c0;
                c_row[j+1] = c1;
                c_row[j+2] = c2;
                c_row[j+3] = c3;
                c_row[j+4] = c4;
                c_row[j+5] = c5;
                c_row[j+6] = c6;
                c_row[j+7] = c7;
            }
            for (; j < N; ++j) {
                c_row[j] += a_val * b_row[j];
            }
        }
    }
}
